            authnRequest.SetAttribute("xmlns:saml", SamlAssertionNamespace);

            // Set AuthnRequest attributes
            authnRequest.SetAttribute("ID", "_" + Guid.NewGuid().ToString("N")); // Unique ID for this request
            authnRequest.SetAttribute("Version", "2.0");
            authnRequest.SetAttribute("IssueInstant", DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ssZ"));
            authnRequest.SetAttribute("AssertionConsumerServiceURL", assertionConsumerServiceUrl);
            authnRequest.SetAttribute("ProtocolBinding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"); // Common binding
            authnRequest.SetAttribute("Destination", idpDestinationUrl);

            // Add Issuer element
            XmlElement issuer = doc.CreateElement("saml", "Issuer", SamlAssertionNamespace);
            issuer.InnerText = issuerId;
