@page
@model IndexModel
@{
    ViewData["Title"] = "SAML AuthnRequest Generator";
}

<div class="text-center">
    <h1 class="display-4">SAML AuthnRequest Generator</h1>
</div>

<div class="row">
    <div class="col-md-8 offset-md-2">
        <form method="post">
            <h2 class="mt-4">SAML Request Configuration</h2>
            <div class="form-group">
                <label asp-for="AssertionConsumerServiceUrl" class="form-label"></label>
                <input asp-for="AssertionConsumerServiceUrl" class="form-control" />
                <small class="form-text text-muted">The URL where the IdP should send the SAML Response.</small>
            </div>
            <div class="form-group mt-3">
                <label asp-for="IssuerId" class="form-label"></label>
                <input asp-for="IssuerId" class="form-control" />
                <small class="form-text text-muted">Your Service Provider (SP) Entity ID.</small>
            </div>
            <div class="form-group mt-3">
                <label asp-for="IdpDestinationUrl" class="form-label"></label>
                <input asp-for="IdpDestinationUrl" class="form-control" />
                <small class="form-text text-muted">The Identity Provider (IdP) SSO URL.</small>
            </div>
            <div class="form-group mt-3">
                <label asp-for="SensitiveData" class="form-label"></label>
                <input asp-for="SensitiveData" class="form-control" />
                <small class="form-text text-muted">This data will be encrypted within a custom <code>&lt;saml:CustomSensitiveInfo&gt;</code> element inside the AuthnRequest. Note: This is a non-standard SAML AuthnRequest pattern, for demonstration of encryption.</small>
            </div>
            <button type="submit" class="btn btn-primary mt-4">Generate SAML AuthnRequest</button>
        </form>

        @if (!string.IsNullOrEmpty(Model.ErrorMessage))
        {
            <div class="alert alert-danger mt-4" role="alert">
                <h3>Error:</h3>
                <pre class="alert-pre">@Model.ErrorMessage</pre>
            </div>
        }

        @if (!string.IsNullOrEmpty(Model.GeneratedSamlXml))
        {
            <div class="mt-5">
                <h2>Generated SAML AuthnRequest XML:</h2>
                <div class="form-group mt-3">
                    <label class="form-label">Signing Certificate Thumbprint:</label>
                    <input type="text" class="form-control" value="@Model.CertificateThumbprint" readonly />
                    <small class="form-text text-muted">This is the thumbprint of the ephemeral self-signed certificate used for signing.</small>
                </div>
                <div class="form-group mt-3">
                    <label class="form-label">TripleDES Encryption Key (Base64):</label>
                    <input type="text" class="form-control" value="@Model.EncryptionKeyBase64" readonly />
                    <small class="form-text text-muted">This is the symmetric key used for encrypting the sensitive data. In a real scenario, this key would be securely shared or exchanged.</small>
                </div>
                <div class="form-group mt-3">
                    <label class="form-label">TripleDES Encryption IV (Base64):</label>
                    <input type="text" class="form-control" value="@Model.EncryptionIvBase64" readonly />
                    <small class="form-text text-muted">This is the Initialization Vector used for encrypting the sensitive data.</small>
                </div>
                <label class="form-label mt-3">SAML AuthnRequest XML:</label>
                <textarea class="form-control" rows="15" readonly style="font-family: monospace; white-space: pre; overflow-x: auto;">@Model.GeneratedSamlXml</textarea>
                <button class="btn btn-secondary mt-3" onclick="copyToClipboard()">Copy XML</button>
            </div>
        }
    </div>
</div>

@section Scripts {
    <script>
        function copyToClipboard() {
            var textarea = document.querySelector('textarea');
            textarea.select();
            document.execCommand('copy');
            alert('XML copied to clipboard!');
        }
    </script>
}